import React from 'react';
import { Link } from 'react-router-dom';

const Navbar: React.FC = () => {
    return (
        <nav className="sticky top-0 z-50 bg-[#020202]/90 backdrop-blur-xl border-b border-white/10">
            {/* Executive Boardroom Gradient Line - Emerald & Burnished */}
            <div className="h-[2px] w-full bg-gradient-to-r from-transparent via-[#004D2C] to-[#99814D] opacity-50"></div>

            <div className="container mx-auto px-6">
                <div className="flex justify-between items-center h-20">

                    {/* Logo: Mixing the Serif vibe with Bold UI */}
                    <Link to="/" className="group relative flex items-center gap-3">
                        <div className="absolute -inset-2 bg-[#004D2C]/20 blur-xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
                        <span className="text-3xl relative">🏙️</span>
                        <div className="relative flex flex-col tracking-tighter">
                            <span className="text-2xl font-black leading-none font-inter">
                                <span className="text-[#004D2C]">CLT</span>
                                <span className="text-[#99814D]">ourism</span>
                            </span>
                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] mt-1 font-inter">Queen City</span>
                        </div>
                    </Link>

                    {/* Navigation: Tech Labels */}
                    <div className="hidden md:flex items-center space-x-10">
                        {[
                            { name: 'Home', path: '/' },
                            { name: 'Map', path: '/map' },
                            { name: 'Itinerary', path: '/itinerary' },
                            { name: 'Login', path: '/login' }
                        ].map((item) => (
                            <Link
                                key={item.name}
                                to={item.path}
                                className="label-tech chromatic-aberration text-slate-400 hover:text-[#004D2C] group transition-colors duration-300"
                            >
                                {item.name}
                                <span className="absolute -bottom-2 left-0 w-0 h-0.5 bg-[#004D2C] transition-all duration-300 group-hover:w-full"></span>
                            </Link>
                        ))}

                        {/* Profile Button - Tech Label */}
                        <Link to="/profile" className="label-tech-luxury chromatic-aberration relative px-6 py-2 rounded-xl transition-all duration-300 group overflow-hidden border border-white/10">
                            <span className="absolute inset-0 bg-slate-800 group-hover:bg-[#99814D] transition-colors duration-500"></span>
                            <span className="relative z-10">Profile</span>
                        </Link>
                    </div>
                </div>
            </div>
        </nav>
    );
};

export default Navbar;
